import{_ as t,c as p,o,U as n}from"./chunks/framework.9QHaLlVJ.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"doc/编程语言/PHP/实战/Content-Type.md","filePath":"packages/doc/src/编程语言/PHP/实战/Content-Type.md","lastUpdated":1705215825000}'),e={name:"doc/编程语言/PHP/实战/Content-Type.md"},a=n('<p><strong>1.application/x-www-form-<strong><strong>urlencoded</strong></strong>（表单EncType默认方式）</strong></p><p>表名窗体数据被编码为名称/值对;</p><p>get请求采用此编码方式</p><p>$_POST与$_GET中填入的是经过urldecode的数据！！！</p><p><strong>2.multipart/form-data</strong></p><p>窗体数据被编码为一条消息，</p><p>当action为post时候，浏览器把form数据封装到http body中，然后发送到server。 如果没有type=file的控件，用默认的application/x-www-form-urlencoded就可以了。 但是如果有type=file的话，就要用到multipart/form-data了。浏览器会把整个表单以控件为单位分割，并为每个部分加上<strong>Content-Disposition(form-data或者file),Content-Type(默认为text/plain),name(控件name)等信息</strong>，并加上分割符(boundary)。，</p><p><strong>3.text/plain</strong></p><p>窗体数据以纯文本形式进行编码，其中不含任何控件或格式字符。</p><p><strong>4.application/json</strong></p><p>该编码方式把窗体数据序列化为一个json字符串放入了http body体中！！！</p><p>5.<strong>PHP的$_POST</strong>，<strong>$GLOBALS [&quot;HTTP_RAW_POST_DATA&quot;]</strong>，<strong>file_get_contents(&#39;php://input&#39;)</strong></p><p><strong>比如 text/xml 或者 soap</strong></p><p>​ <img src="https://note.youdao.com/yws/public/resource/524333cb6097c37f19e2e000a50a67af/xmlnote/F6C53243DEF84362BBF08B4C0405459F/10124" alt="0"></p><p>当 HTTP POST 请求的 Content-Type 是 <em>application/x-www-form-urlencoded</em> 或 <em>multipart/form-data</em> 时，会将变量以关联数组形式传入当前脚本。</p><p>所以碰到application/json格式的数据使用$_POST获取不到的！！！</p><p><strong>①可以通过$GLOBALS [&quot;HTTP_RAW_POST_DATA&quot;]或者file_get_contents(&#39;php://input&#39;)来获取数据，但是获取的只是字符串而已，需要json_decode！！！</strong></p><p>②对于**$GLOBALS [&quot;HTTP_RAW_POST_DATA&quot;]**需要设置php.ini中的always_populate_raw_post_data值为On，PHP才会总把POST数据填入变量$http_raw_post_data。</p><p>③php://input 不能用于 enctype=&quot;multipart/form-data&quot;。</p><p>区别：</p><p><strong>1，Coentent-Type仅在取值为application/x-www-data-urlencoded和multipart/form- data两种情况下，PHP才会将http请求数据包中相应的数据填入全局变量$_POST 2，PHP不能识别的Content-Type类型的时候，会将http请求包中相应的数据填入变量$HTTP_RAW_POST_DATA 3, 只有Coentent-Type为multipart/form-data的时候，PHP不会将http请求数据包中的相应数据填入php: //input，否则其它情况都会。填入的长度，由Coentent-Length指定。 4，只有Content-Type为application/x-www-data-urlencoded时，php://input数据才 跟$_POST数据相一致。 5，php://input数据总是跟$HTTP_RAW_POST_DATA相同，但是php://input 比$HTTP_RAW_POST_DATA更凑效，且不需要特殊设置php.ini 6，PHP会将PATH字段的query_path部分，填入全局变量$_GET。通常情况下，GET方法提交的http请求，body为空。</strong></p>',21),r=[a];function s(_,i,T,c,d,P){return o(),p("div",null,r)}const m=t(e,[["render",s]]);export{u as __pageData,m as default};
